import React, { useEffect, useState } from 'react';

const IndexPage = () => {
    const [data, setData] = useState(null);

    useEffect(() => {
        fetch('/data.json')
            .then(r => r.json())
            .then(setData)
            .catch(() => { });
    }, []);

    return (
        <main style={{ fontFamily: 'sans-serif', padding: 20 }}>
            <h1>Gatsby Data Server</h1>
            <p>
                Merged data is available at <a href="/data.json">/data.json</a>
            </p>
            <pre style={{ whiteSpace: 'pre-wrap', background: '#f7f7f7', padding: 12 }}>
                {data ? JSON.stringify(data, null, 2) : 'Loading...'}
            </pre>
        </main>
    );
};

export default IndexPage;
